Another subtlety is that the way Solidity works, it's not really possible to tell the difference between a struct being returned, and an annotated tuple.

This contract:
```solidity
pragma solidity ^0.4.24;
contract A {
  struct MyStruct {
    uint a;
    uint b;
  }
  MyStruct public myStruct;
  mapping (address => MyStruct) public myMapping;
  
  function myFunction() public pure returns (uint a, uint b) {
      return (0, 1);
  }
}
```
has the ABI:
```json
[{"constant":true,"inputs":[{"name":"","type":"address"}],"name":"myMapping","outputs":[{"name":"a","type":"uint256"},{"name":"b","type":"uint256"}],"payable":false,"stateMutability":"view","type":"function"},{"constant":true,"inputs":[],"name":"myStruct","outputs":[{"name":"a","type":"uint256"},{"name":"b","type":"uint256"}],"payable":false,"stateMutability":"view","type":"function"},{"constant":true,"inputs":[],"name":"myFunction","outputs":[{"name":"a","type":"uint256"},{"name":"b","type":"uint256"}],"payable":false,"stateMutability":"pure","type":"function"}]
```
which all three of `myStruct()`, `myMapping(address)` and `myFunction()` have a return type with outputs `[{"name":"a","type":"uint256"},{"name":"b","type":"uint256"}]`, so this solution will have to be a bit more generic than assuming that return type is always a struct

Vyper doesn't allow naming returns, so a struct will always have named members, and a tuple will be all `out`:
```python
myStruct: public({
    a: uint256,
    b: uint256
})
myMapping: public({
    a: uint256,
    b: uint256
}[address])

@public
@constant
def myFunction() -> (uint256, uint256):
    return (0, 1)
```
has ABI:
```json
[{"name": "myFunction", "outputs": [{"type": "uint256", "name": "out"}, {"type": "uint256", "name": "out"}], "inputs": [], "constant": true, "payable": false, "type": "function", "gas": 355}, {"name": "myStruct__a", "outputs": [{"type": "uint256", "name": "out"}], "inputs": [], "constant": true, "payable": false, "type": "function", "gas": 585}, {"name": "myStruct__b", "outputs": [{"type": "uint256", "name": "out"}], "inputs": [], "constant": true, "payable": false, "type": "function", "gas": 621}, {"name": "myMapping__a", "outputs": [{"type": "uint256", "name": "out"}], "inputs": [{"type": "address", "name": "arg0"}], "constant": true, "payable": false, "type": "function", "gas": 817}, {"name": "myMapping__b", "outputs": [{"type": "uint256", "name": "out"}], "inputs": [{"type": "address", "name": "arg0"}], "constant": true, "payable": false, "type": "function", "gas": 853}]
```
which is even weirder

